        [Fact]
        public async Task Test_SmokeStreamingOpenai()
        {
            // Chat streaming against real OpenAI API, verifies chunks received
            var apiKey = System.Environment.GetEnvironmentVariable("OPENAI_API_KEY");
            var baseUrl = string.IsNullOrEmpty(apiKey)
                ? (System.Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? string.Empty) + "/fixtures/smoke_streaming_openai"
                : null;
            Console.WriteLine($"smoke_streaming_openai: " + (baseUrl == null ? "using real API (OPENAI_API_KEY is set)" : "using mock server (OPENAI_API_KEY not set)"));
            var client = LiterLlmLib.CreateClient(string.IsNullOrEmpty(apiKey) ? "test-key" : apiKey, baseUrl, null, null, null);
            var chunks = new List<ChatCompletionChunk>();
            var streamContent = new System.Text.StringBuilder();
            var streamComplete = false;
            await foreach (var chunk in client.ChatStreamAsync(ChatCompletionRequest.FromJson("{\"max_tokens\":50,\"messages\":[{\"content\":\"Count from 1 to 5.\",\"role\":\"user\"}],\"model\":\"openai/gpt-4o-mini\"}")))
            {
                chunks.Add(chunk);
                var choice = chunk.Choices != null && chunk.Choices.Count > 0 ? chunk.Choices[0] : null;
                if (choice != null)
                {
                    var delta = choice.Delta;
                    if (delta != null && !string.IsNullOrEmpty(delta.Content))
                    {
                        streamContent.Append(delta.Content);
                    }
                }
            }
            streamComplete = true;
            Assert.True(chunks.Count >= 1, "expected at least 1 chunks");
            Assert.True(streamComplete);
        }

